fun close() = KoinPlatformTools.synchronized(this) {
    _koin.logger.debug("|- (-) Scope - id:'$id'")

    _callbacks.forEach { it.onScopeClose(this) }
    _callbacks.clear()
    _closed = true

    sourceValue = null

    _parameterStack?.get()?.clear()
    _parameterStack = null

    _koin.scopeRegistry.deleteScope(this)
}

