}

internal fun parseType(name: String): TypeName? {
  val className = ClassName.bestGuess(name.substringBefore('<').withPackage())
  val typeArgs = name.substringAfter('<', "").substringBefore('>', "")
      .split(',')
      .filterNot { it.isEmpty() }
      .map { it.trim() }
  return if (typeArgs.isEmpty()) {
    className
  } else {
    ParameterizedTypeName.get(className, *typeArgs.map { parseType(it) }.toTypedArray())
  }
}

fun build(): TypeSpec {
  return TypeSpec.classBuilder(JavaClassNames.Builder.simpleName())
      .addModifiers(Modifier.PUBLIC, Modifier.STATIC, Modifier.FINAL)
      .addAnnotation(suppressAnnotation("unchecked"))
      .addFields(builderFields())
      .addMethod(MethodSpec.constructorBuilder().build())
      .addMethods(fieldSetterMethodSpecs())
      .addMethod(buildMethod())
      .build()
}

@RaiseDSL @IgnorableReturnValue
@OptIn(ExperimentalExtendedContracts::class)
public inline fun <Error, B : Any> Raise<Error>.ensureNotNull(value: B?, raise: () -> Error): B {
  contract {
    callsInPlace(raise, AT_MOST_ONCE)
    returns() implies (value != null)
    (value == null) holdsIn raise
  }
  return value ?: raise(raise())
}

@RaiseDSL
public inline fun <Error, OtherError, A> Raise<Error>.withError(
  transform: (OtherError) -> Error,
  block: Raise<OtherError>.() -> A
): A {
  contract {
    callsInPlace(block, EXACTLY_ONCE)
    callsInPlace(transform, AT_MOST_ONCE)
  }
  recover({ return block() }) { raise(transform(it)) }
}

